require(['jquery', 'bootstrap'], function($) {
  // Don't follow the category link on click. Just expand/collapse the category.
  $(document).on('click', '.admin-menu a.panel-heading', function(event) {
    event.preventDefault();
  });
  // Mark the administration menu as ready for user interaction.
  $('.admin-menu').attr('data-ready', true);
});

/**
 * Live search in the category/section name and description.
 */
require(['jquery'], function($) {
  var filterItem = function(text) {
    var name = $(this).text().toLowerCase();
    var description = ($(this).attr('title') || '').toLowerCase();
    return typeof text === 'string' && name.indexOf(text) < 0 && description.indexOf(text) < 0;
  };

  var filterPanelGroup = function(text) {
    var panelGroup = $(this);
    // Filter the sections.
    panelGroup.find('.list-group-item').each(function() {
      $(this).toggleClass('hidden', filterItem.call(this, text));
    });
    // Filter the categories.
    panelGroup.find('a.panel-heading').each(function() {
      var panel = $(this).closest('.panel');
      var hasVisibleSections = panel.find('.list-group-item').not('.hidden').length > 0;
      var matchesFilterQuery = !filterItem.call($(this), text);
      panel.toggle(hasVisibleSections || matchesFilterQuery);
      if (!hasVisibleSections && matchesFilterQuery) {
        // If the filter query matches only the category name/description and none of its sections name/description then
        // show all the sections.
        panel.find('.list-group-item').removeClass('hidden');
      }
      // Fix the style (round corners) of the last visible section in each category.
      panel.find('.list-group-item.last').removeClass('last');
      panel.find('.list-group-item').not('.hidden').last().addClass('last');
    });
    // Expand the first visible category, if there is a filter query.
    if (typeof text === 'string' && text !== '') {
      // We expand the category manually, instead of using the JavaScript API of Bootstrap Collapse, because we can't
      // disable the animation.
      panelGroup.find('.panel-collapse.in').removeClass('in')
        .prev('.panel-heading').addClass('collapsed').attr('aria-expanded', false);
      panelGroup.find('a.panel-heading').filter(':visible').first()
        .removeClass('collapsed').attr('aria-expanded', true)
        // Remove the height:0px in-line style added by the collapse animation because it breaks the border styles.
        .next('.panel-collapse').addClass('in').css('height', '');
    }
    // Show/Hide the "No results." message.
    var hasVisibleCategories = panelGroup.find('a.panel-heading').filter(':visible').length > 0;
    panelGroup.find('.noitems').toggleClass('hidden', hasVisibleCategories);
  };

  var timeoutId;
  $('.panel-group-filter').on('input', function() {
    // Cancel the previously scheduled filter operation.
    clearTimeout(timeoutId);
    var panelGroup = $(this).closest('.panel-group');
    var text = $(this).val().toLowerCase();
    // Schedule a new filter operation.
    timeoutId = setTimeout(filterPanelGroup.bind(panelGroup, text), 500);

  // Finally, enable the search input.
  }).prop('disabled', false);
});

#template('colorThemeInit.vm')

#admin-page-content h2.wikigeneratedheader,
#admin-page-content .xform h2 {
  border-bottom: 1px solid $theme.borderColor;
  font-size: 150%;
  line-height: inherit;
  margin-bottom: 1em;
}

#admin-page-content h2.wikigeneratedheader:first-of-type,
#admin-page-content .xform h2:first-of-type {
  margin-top: 0;
}

#admin-page-content label > input[type="checkbox"] {
  vertical-align: middle;
}

#admin-page-content label > input[type="radio"] {
  vertical-align: baseline;
}

#admin-page-content .usersorgroupsnames label > input[type="radio"] {
  vertical-align: unset;
}

/**
 * Category Overview
 */
.admin-categories-container p {
  margin: 0;
}
.admin-categories-container{
  float: left;
  display: flex;
  gap: 8px;
  flex-flow: column;
}
.admin-category-card {
  display: flex;
  gap: 0 8px;
  border-radius: 7px;
  padding: 4px;
}

.admin-category-text-container {
  display: flex;
  flex-flow: column;
  justify-content: center;
}
.admin-category-icon {
  flex-shrink: 0;
  padding: 16px;
  background-color: #fafafa; /* Ideally we'd want to use a variable, but we need to ensure visibility on dark themes */
  display:flex;
  justify-content: center;
  align-items: center;
  border-radius: 7px;
  border: 1px solid var(--xwiki-border-color);
}

.admin-category-name {
  font-size: 1.44em;
  font-weight: var(--font-weight-semibold);
}

.admin-category-description {
  color: var(--text-muted);
}

/**
 * Users & Rights
 */

/* Override general table styles. */
/* TODO: Move to livetable.css */

#usersandgroupstable td, #alldocstable td {
  border-color: transparent;
}

#admin-page-content .usersorgroupsnames {
  white-space: nowrap;
  /* Triple of the value for the .right column. This is useful to make sure the columns are somewhat balanced when
    there is only one right (e.g., extension rights with a default flavor).
    Keeping them balanced is useful to make sure the filters are displayed properly, which is especially important
    on a subwiki where we have to find a place to display the scope selector. */
  width: 27%;
}

#usersandgroupstable-filters-scope {
  white-space: nowrap;
}

#usersandgroupstable-filters #name {
    width: 65%;
}

.rights-settings {
  margin-top: 20px;
  margin-left: 5px;
}

.rights-settings dt {
  /* The labels for the general rights settings are long and thus look bad when displayed with bold text. */
  font-weight: normal;
}

.rights-settings dt input {
  vertical-align: top;
}

.xform #usersandgroupstable select {
  width: unset;
}

/**
 * Bootstrap's Accordion Menu
 */

.admin-menu {
  /* Align the menu with the page title. */
  padding-left: 0;
}

.admin-menu .panel-heading.collapsed {
  border-bottom-left-radius: 5px;
  border-bottom-right-radius: 5px;
}

.admin-menu a.panel-heading {
  display: flex;
  font-size: 100%;
}

.admin-menu a.panel-heading span {
  flex-grow: 1;
}

.admin-menu a.panel-heading:not(.collapsed) {
  background-color: $theme.menuBackgroundColor;
  color: $theme.menuLinkColor;
}

/* Rotate the carret on collapse. */
.admin-menu a.panel-heading.collapsed > *:last-child {
  transform: rotate(90deg);
}

.admin-menu a.panel-heading > *:last-child {
  transition: transform 200ms ease-in-out;
}

.admin-menu a.panel-heading:active,
.admin-menu a.panel-heading:focus,
.admin-menu a.panel-heading:hover {
  text-decoration: none;
}

.admin-menu .panel-heading > span > *:first-child {
  margin-right: .8em;
}

.admin-menu .panel-collapse > .list-group:last-child .list-group-item.last {
  border-bottom-right-radius: 5px;
  border-bottom-left-radius: 5px;
}

.admin-menu .panel.noitems > .panel-heading {
  color: $theme.textSecondaryColor;
}
